              {entry.dataKey === 'likes' && <IconHeart style={{ color: entry.color }} />}
              {entry.dataKey === 'comments' && <IconMessage style={{ color: entry.color }} />}
              {entry.dataKey === 'shares' && <IconShare style={{ color: entry.color }} />}
