              {typeof children === 'function' ? children(values) : children}
              {closeButton && isDismissable && <DialogX />}
            </>
          )}
        </RACDialog>
      </RACModal>
    </DialogOverlay>
  )
}

const DialogHeader = ({ className, ...props }: ComponentPropsWithRef<'div'>) => {
